{{CSS|content=@import url('https://fonts.googleapis.com/css2?family=Playfair+Display:wght@400;500;700&family=Poiret+One&display=swap');

:root {
  --casino-black: 12, 12, 12;
  --casino-darkgreen: 8, 90, 48;
  --casino-green: 28, 140, 78;
  --casino-red: 210, 38, 48;
  --casino-gold: 218, 165, 32;
  --casino-cream: 245, 245, 235;
  --casino-shadow: 0, 0, 0;

  --body-font: 'Playfair Display', serif;
  --retro-font: 'Poiret One', cursive;
}

.page-container .page {
  position: relative;
  border: 4px solid rgb(var(--casino-gold));
  border-image: linear-gradient(to bottom, rgb(var(--casino-gold)), rgba(var(--casino-gold), 0.4)) 1;
  margin: 16px auto;
  max-width: 1280px;
  border-radius: 12px;
  overflow: hidden;
  box-shadow: 
    0 12px 36px rgba(var(--casino-shadow), 0.7),
    inset 0 0 24px rgba(var(--casino-darkgreen), 0.55),
    inset 0 4px 12px rgba(var(--casino-gold), 0.15);
  background: 
    radial-gradient(circle at 30% 20%, rgba(var(--casino-gold), 0.08), transparent 60%),
    linear-gradient(145deg, 
      rgb(var(--casino-black)) 0%,
      rgb(var(--casino-darkgreen)) 38%,
      rgba(var(--casino-green), 0.18) 68%,
      rgba(var(--casino-black), 0.92) 100%
    );
  background-image: 
    repeating-linear-gradient(0deg, rgba(var(--casino-cream), 0.03) 0px, transparent 3px, transparent 6px),
    repeating-linear-gradient(90deg, rgba(var(--casino-cream), 0.03) 0px, transparent 3px, transparent 6px);
}

.theme-fandomdesktop-dark {
  --theme-page-background-color: rgb(var(--casino-black));
  --theme-page-background-color--secondary: rgba(var(--casino-darkgreen), 0.22);
  --theme-link-color: rgb(var(--casino-gold));
  --theme-border-color: rgb(var(--casino-red));
  --theme-community-header-color: rgb(var(--casino-green));
  --theme-sticky-nav-background-color: rgba(var(--casino-black), 0.96);
  --theme-sticky-nav-text-color: rgb(var(--casino-cream));
  --theme-sticky-nav-text-color--hover: rgb(var(--casino-gold));
}

.theme-fandomdesktop-light {
  --theme-page-background-color: rgba(var(--casino-cream), 0.94);
  --theme-page-background-color--secondary: rgb(var(--casino-black));
  --theme-link-color: rgb(var(--casino-red));
  --theme-border-color: rgb(var(--casino-gold));
  --theme-community-header-color: rgb(var(--casino-darkgreen));
  --theme-sticky-nav-background-color: rgba(var(--casino-cream), 0.97);
  --theme-sticky-nav-text-color: rgb(var(--casino-black));
  --theme-sticky-nav-text-color--hover: rgb(var(--casino-red));
}

a,
a:visited {
  color: rgb(var(--casino-gold)) !important;
  text-decoration: none;
  transition: color 0.4s ease, text-shadow 0.4s ease;
}

a:hover,
a:focus {
  color: rgb(var(--casino-red)) !important;
  text-shadow: 
    0 0 8px rgba(var(--casino-red), 0.8),
    0 0 16px rgba(var(--casino-gold), 0.6);
}

.page-side-tools .page-side-tool {
  border: 3px solid rgb(var(--casino-gold));
  box-shadow: 0 0 12px rgba(var(--casino-gold), 0.45);
  border-radius: 50%;
  background-color: rgba(var(--casino-black), 0.92);
  transition: all 0.35s ease;
  position: relative;
  overflow: hidden;
}

.page-side-tool::before {
  content: '';
  position: absolute;
  inset: 0;
  background: radial-gradient(circle at 30% 30%, rgba(var(--casino-gold), 0.25), transparent 70%);
  opacity: 0;
  transition: opacity 0.35s ease;
}

.page-side-tool:hover {
  transform: scale(1.12) rotate(3deg);
  box-shadow: 0 0 24px rgba(var(--casino-red), 0.7), 0 0 40px rgba(var(--casino-gold), 0.5);
}

.page-side-tool:hover::before {
  opacity: 1;
}

.titleblock, .dark-titleblock {
  background: 
    radial-gradient(circle at top left, rgba(var(--casino-gold), 0.22), transparent 70%),
    radial-gradient(circle at bottom right, rgba(var(--casino-red), 0.15), transparent 70%),
    linear-gradient(135deg, rgba(var(--casino-black), 0.98), rgba(var(--casino-darkgreen), 0.85));
  border: 4px double rgb(var(--casino-gold));
  border-radius: 14px;
  padding: 1.4rem 2rem;
  font-family: var(--retro-font);
  font-weight: 400;
  color: rgb(var(--casino-cream));
  text-shadow: 
    0 0 8px rgba(var(--casino-gold), 0.9),
    0 0 16px rgba(var(--casino-red), 0.6),
    0 0 24px rgba(var(--casino-gold), 0.4);
  font-size: 2.8em;
  letter-spacing: 5px;
  transform: rotate(-0.6deg);
  animation: luxurious-glow 6s ease-in-out infinite alternate;
  position: relative;
}

.titleblock::after, .dark-titleblock::after {
  content: '♦ ♥ ♠ ♣';
  position: absolute;
  bottom: 0.4rem;
  right: 1.2rem;
  font-size: 0.7em;
  opacity: 0.6;
  letter-spacing: 8px;
}

.progress {
  background: rgba(var(--casino-black), 0.94);
  border: 3px solid rgb(var(--casino-gold));
  border-radius: 10px;
  color: rgb(var(--casino-cream));
  box-shadow: 0 0 14px rgba(var(--casino-gold), 0.5);
  overflow: hidden;
}

.progress .bar {
  background: linear-gradient(90deg, 
    rgb(var(--casino-red)) 0%, 
    rgb(var(--casino-gold)) 40%, 
    rgb(var(--casino-green)) 70%, 
    rgb(var(--casino-gold)) 100%
  );
  border-radius: 7px;
  box-shadow: 0 0 18px rgba(var(--casino-gold), 0.7);
  background-size: 200% 100%;
  animation: shimmer 4s linear infinite;
}

@keyframes shimmer {
  0% { background-position: 200% 0; }
  100% { background-position: -200% 0; }
}

h1, h2, h3, h4, h5, h6 {
  font-family: var(--retro-font);
  color: rgb(var(--casino-cream));
  text-transform: uppercase;
  letter-spacing: 7px;
  text-shadow: 
    0 0 10px rgba(var(--casino-gold), 0.85),
    0 0 20px rgba(var(--casino-red), 0.65),
    0 0 30px rgba(var(--casino-gold), 0.45);
  font-size: calc(1.6rem + 0.9vw);
}

h1 {
  font-size: calc(2.6rem + 1.3vw);
}

@keyframes luxurious-glow {
  0%, 100% {
    text-shadow: 
      0 0 10px rgba(var(--casino-gold), 1),
      0 0 20px rgba(var(--casino-red), 0.7),
      0 0 30px rgba(var(--casino-gold), 0.5);
    opacity: 1;
  }
  50% {
    text-shadow: 
      0 0 6px rgba(var(--casino-gold), 0.7),
      0 0 14px rgba(var(--casino-red), 0.5),
      0 0 22px rgba(var(--casino-gold), 0.35);
    opacity: 0.96;
  }
}
}}
